mapper.select:
/* adm-master-calendar-sql-oracle-xml - selectCalendar */ #{GRIDPAGING_ROWNUMTYPE_TOP} SELECT '0' AS CHK ,CFULLDATE ,CYEAR ,CMONTH ,CDATE ,'WEEKDAY' || ';' || DAYWEEK AS DAYWEEK_DESC ,DAYWEEK ,DAYTITLE ,'YESORNO' || ';' || ISBASICHOLIDAY AS ISBASICHOLIDAY_DESC ,ISBASICHOLIDAY ,'YESORNO' || ';' || ISEXTRAHOLIDAY AS ISEXTRAHOLIDAY_DESC ,ISEXTRAHOLIDAY ,INSERTDATE ,UPDATEDATE ,INSERTURKEY ,UPDATEURKEY FROM TADMIN_MST_CAL A
AND #{SEARCH_CONDITION}
ORDER BY #{colName} DESC
ORDER BY #{colName} ASC
ORDER BY CFULLDATE DESC
#{GRIDPAGING_ROWNUMTYPE_BOTTOM}

/* adm-master-calendar-sql-oracle-xml - selectCalendarCount */
	SELECT COUNT(1)  
	  FROM TADMIN_MST_CAL A


		   AND #{SEARCH_CONDITION}

mapper.insert:
/* adm-master-calendar-sql-oracle-xml - insertCalendar */

	INSERT INTO TADMIN_MST_CAL(
		   CFULLDATE
		  ,CYEAR
		  ,CMONTH
		  ,CDATE
		  ,DAYWEEK
		  ,DAYTITLE
		  ,ISBASICHOLIDAY
		  ,ISEXTRAHOLIDAY
		  ,INSERTDATE
		  ,INSERTURKEY
		  ,UPDATEDATE
		  ,UPDATEURKEY
	    ) VALUES (
		  	 #{cfulldate}
		  	,#{cyear}
		  	,#{cmonth}
		  	,#{cdate}
		  	,#{dayweek}
		  	,#{daytitle}
		  	,#{isbasicholiday}
		  	,#{isextraholiday}
			,#{sysdate}
			,#{surkey}
			,#{sysdate}
			,#{surkey}
		)

mapper.update:
/* adm-master-calendar-sql-oracle-xml - updateCalendar */
	UPDATE TADMIN_MST_CAL 
	   SET
		  DAYTITLE = #{daytitle}      
		 ,ISBASICHOLIDAY = #{isbasicholiday}
		 ,ISEXTRAHOLIDAY = #{isextraholiday}
		 ,UPDATEDATE = #{sysdate}
		 ,UPDATEURKEY = #{surkey}
	WHERE 
		  CFULLDATE	= #{cfulldate}

mapper.delete:
/* adm-master-calendar-sql-oracle-xml - deleteCalendar */
	DELETE 
	  FROM TADMIN_MST_CAL
	 WHERE CFULLDATE	= #{cfulldate}
